B.TF=new A.df("\xbfQu\xe9 es?","SUNAT (Superintendencia Nacional de Aduanas y de Administraci\xf3n Tributaria) es el organismo del Estado Peruano encargado de administrar, fiscalizar y recaudar los tributos internos del gobierno nacional.")
B.TH=new A.df("\xbfQu\xe9 hace SUNAT?","\u2022 Recauda impuestos como el IGV e Impuesto a la Renta\n\u2022 Controla el cumplimiento de obligaciones tributarias\n\u2022 Facilita el comercio exterior\n\u2022 Orienta a los contribuyentes sobre sus obligaciones\n\u2022 Sanciona a quienes evaden impuestos")
B.TE=new A.df("\xbfPor qu\xe9 te importa?","Si generas ingresos en Per\xfa \u2014 sea como dependiente, independiente o empresario \u2014 tienes obligaciones con SUNAT. Conocerlas te evita multas, problemas legales y te permite aprovechar beneficios tributarios.")
B.KU=A.a(s([B.TF,B.TH,B.TE]),t.GN)
B.Ts=new A.eY("tax_1","\xbfQu\xe9 es SUNAT?","La entidad que recauda impuestos en Per\xfa","\ud83c\udfdb\ufe0f","3 min",B.KU,B.a9)
B.TC=new A.df("\xbfQu\xe9 es el RUC?","El RUC (Registro \xdanico de Contribuyentes) es un n\xfamero de identificaci\xf3n de 11 d\xedgitos que te asigna SUNAT cuando te registras como contribuyente. Es como tu DNI, pero para temas tributarios.")
B.TG=new A.df("\xbfQui\xe9n necesita RUC?","\u2022 Personas que realizan actividades econ\xf3micas de forma independiente\n\u2022 Empresas y negocios de cualquier tama\xf1o\n\u2022 Personas que alquilan propiedades\n\u2022 Profesionales freelance (contadores, dise\xf1adores, desarrolladores, etc.)")
B.TD=new A.df("\xbfC\xf3mo obtenerlo?","Puedes tramitarlo:\n\u2022 En la web de SUNAT (sunat.gob.pe)\n\u2022 En cualquier oficina de SUNAT a nivel nacional\n\u2022 Con tu DNI y datos b\xe1sicos del negocio o actividad")
B.TI=new A.df("Tip importante","Tener RUC activo te permite emitir comprobantes de pago, lo que muchos clientes formales requieren para hacer negocios contigo.")
B.Lq=A.a(s([B.TC,B.TG,B.TD,B.TI]),t.GN)
B.Tq=new A.eY("tax_2","\xbfQu\xe9 es el RUC?","Tu identidad tributaria en Per\xfa","\ud83e\udeaa","4 min",B.Lq,B.Y)
B.TA=new A.df("\xbfQu\xe9 es una boleta de venta?","Es el comprobante que se entrega a personas naturales (consumidores finales). No permite deducir IGV, y se emite cuando el comprador no tiene RUC o no necesita factura para su negocio.")
B.Tu=new A.df("\xbfQu\xe9 es una factura?","Es el comprobante que se entrega a empresas o personas con RUC. Permite al comprador deducir el IGV de sus compras como cr\xe9dito fiscal. Es m\xe1s formal y detallada que la boleta.")
B.TB=new A.df("\xbfCu\xe1ndo usar cada una?","\u2713 Boleta: Cliente sin RUC o consumidor final\n\u2713 Factura: Cliente con RUC que necesita deducir impuestos\n\nEjemplo: Si un restaurant te atiende a ti (persona), emite boleta. Si le vendes servicios de dise\xf1o a una empresa, emites factura.")
B.TK=new A.df("Comprobantes electr\xf3nicos","Desde hace varios a\xf1os, SUNAT exige emitir comprobantes electr\xf3nicos (Factura Electr\xf3nica, Boleta Electr\xf3nica). Puedes hacerlo desde la plataforma de SUNAT o usando software autorizado.")
B.Lo=A.a(s([B.TA,B.Tu,B.TB,B.TK]),t.GN)
B.Tr=new A.eY("tax_3","Boleta vs Factura","\xbfCu\xe1l emitir y cu\xe1ndo?","\ud83e\uddfe","5 min",B.Lo,B.X)
B.Tw=new A.df("\xbfQu\xe9 es Cuarta Categor\xeda?","Son los ingresos obtenidos por el ejercicio individual de una profesi\xf3n, arte, ciencia u oficio. Si eres freelancer, consultor, m\xe9dico independiente, abogado, dise\xf1ador, etc., probablemente generas rentas de 4ta categor\xeda.")
B.Tz=new A.df("\xbfQu\xe9 impuesto pagas?","Impuesto a la Renta (IR). La tasa es progresiva:\n\u2022 Hasta 5 UIT: exonerado\n\u2022 De 5 a 20 UIT: 8%\n\u2022 De 20 a 35 UIT: 14%\n\u2022 De 35 a 45 UIT: 17%\n\u2022 M\xe1s de 45 UIT: 20%\n\n(La UIT 2024 = S/. 5,150)")
B.Tx=new A.df("\xbfQu\xe9 es una Recibo por Honorarios?","Es el comprobante que emites cuando cobras por tus servicios independientes. Puedes emitirlo electr\xf3nicamente en el portal de SUNAT. Tu cliente te retiene el 8% como pago anticipado del IR.")
B.Ty=new A.df("Declaraci\xf3n anual","Si tus ingresos anuales superan las 7 UIT (S/. 36,050), debes presentar declaraci\xf3n anual del IR entre marzo y abril del a\xf1o siguiente.")
B.LD=A.a(s([B.Tw,B.Tz,B.Tx,B.Ty]),t.GN)
B.Tp=new A.eY("tax_4","Independientes y Cuarta Categor\xeda","Lo que debes saber si trabajas por tu cuenta","\ud83d\udcbc","6 min",B.LD,B.bl)
B.Tv=new A.df("Error 1: No declarar todos los ingresos","Muchos creen que si cobran en efectivo SUNAT no se entera. Error. SUNAT cruza informaci\xf3n con bancos, clientes y otras fuentes. Siempre declara todos tus ingresos.")
B.TJ=new A.df("Error 2: No emitir comprobantes","No emitir boleta o factura cuando corresponde es una infracci\xf3n sancionada con multas. Siempre entrega comprobante por tus ventas o servicios.")
B.TM=new A.df("Error 3: Mezclar finanzas personales y del negocio","Usa cuentas bancarias separadas para tu negocio y tus gastos personales. Mezclarlas complica la contabilidad y puede generar problemas ante una fiscalizaci\xf3n.")
B.TL=new A.df("Error 4: Ignorar notificaciones de SUNAT","SUNAT notifica por su buz\xf3n electr\xf3nico (clave SOL). Ignorar notificaciones puede derivar en multas adicionales o embargo. Revisa tu buz\xf3n regularmente.")
B.LE=A.a(s([B.Tv,B.TJ,B.TM,B.TL]),t.GN)
B.Tt=new A.eY("tax_5","Errores Tributarios Comunes","Evita multas y problemas con SUNAT","\u26a0\ufe0f","4 min",B.LE,B.aq)
